do 'MontaCalendario'
Do Case Case &DiaClicado = serverdate() &TituloGrid = 'HOJE ' + trim(&DiaClicado.ToFormattedString()) CAse &DiaClicado = (serverdate()-1) &TituloGrid = 'ONTEM ' + trim(&DiaClicado.ToFormattedString()) CAse &DiaClicado = (serverdate()+1) &TituloGrid = 'AMANHÃ ' + trim(&DiaClicado.ToFormattedString()) Otherwise &TituloGrid = cDoW(&DiaClicado) + ' ' + trim(&DiaClicado.ToFormattedString()) EndCase
EndEvent
Event Grid.Load
&gridAgeCod = AgeCod tbNenhum.Visible = 0 txtdia.Caption = padL(trim(str(day(AgeDta))),2, '0') txtMEs.Caption = UPPER(Substr(Cmonth(AgeDta), 1, 3)) txtAno.Caption = trim(str(year(AgeDta))) txtHora.Caption = Substr(AgeHor, 1,5) &AgeCliCod = AgeCliCod if &AgeCliCod.IsEmpty() &PedHisObs = AgeObs else Do 'GetCliente' &PedHisObs = &PesCodRaz + AgeObs EndIf &AgePedCod = AgePedCod
&DadosProcesso = 'Agenda Pessoal do Usuário'
&Aviso.ForeColor = RGB(255,255,255) if DstNom.IsEmpty() &Aviso = 'SEM DESTAQUE' &Aviso.ForeColor = RGB(0,0,0) &Aviso.BackColor = RGB(255,255,255) Else &Aviso = DstNom.Trim() &Aviso.BackColor = RGB(DstR,DstG,DstB) EndIF
Do Case Case AgePesSts = Status_AtivoInativo_Agenda.INATIVO &AvisoStatus = 'INATIVADO' &AvisoStatus.ForeColor = RGB(0,0,0) &AvisoStatus.BackColor = RGB(255,255,255) Case AgePesSts = Status_AtivoInativo_Agenda.CANCELADO &AvisoStatus = 'CANCELADO' &AvisoStatus.ForeColor = RGB(255,255,255) &AvisoStatus.BackColor = RGB(204,51,0) Case AgePesSts = Status_AtivoInativo_Agenda.FINALIZADO &AvisoStatus = 'FINALIZADO' &AvisoStatus.ForeColor = RGB(255,255,255) &AvisoStatus.BackColor = RGB(255,0,0) Otherwise &AvisoStatus.ForeColor = RGB(255,255,255) &AvisoStatus.BackColor = RGB(255,255,255) &AvisoStatus = 'ABERTO' EndCase
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (AgePesSts = Status_AtivoInativo_Agenda.ATIVO) Editar.Visible = True Else Editar.Visible = False Endif If (AgePesSts = Status_AtivoInativo_Agenda.ATIVO) Remover.Visible = True Else Remover.Visible = False Endif If (AgePesSts = Status_AtivoInativo_Agenda.ATIVO) Finalizar.Visible = True Else Finalizar.Visible = False Endif
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
