Sub 'LoadGridState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"EMPCOD" &EmpCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"DIACLICADO" &DiaClicado.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PESCOD" &PesCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"AGEPESSTS" &AgePesSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Else &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState"))
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"AGEPESSTS" &AgePesSts.FromString(&GridStateFilterValue.Value) &AuxAgePesSts = &AgePesSts EndCase EndFor
Endif
EndSub
Sub 'SaveGridState'
if 1=2
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"EMPCOD", "", not &EmpCod.IsEmpty(), 0, &EmpCod.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"DIACLICADO", "", not &DiaClicado.IsEmpty(), 0, &DiaClicado.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"PESCOD", "", not &PesCod.IsEmpty(), 0, &PesCod.ToString().Trim(), '') WWP_GridStateAddFilterValue(&GridState, !"AGEPESSTS", "", not &AgePesSts.IsEmpty(), 0, &AgePesSts, '')
SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
else // Save grid state in session. &GridState.FilterValues.Clear()
If not &AuxAgePesSts.IsEmpty() &GridStateFilterValue = new() &GridStateFilterValue.Name = !"AGEPESSTS" &GridStateFilterValue.Value = &AuxAgePesSts.ToString() &GridState.FilterValues.Add(&GridStateFilterValue) EndIf
SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
Endif
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"Agenda"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'MontaDataBase'
if &SdtDiaMes.Count <= 0 if &DataBase.IsEmpty() &DataBase = serverdate() &DiaClicado = serverdate() EndIF
do 'MontaCalendario' Endif
For &SdtDiaMesItem in &SdtDiaMes if &SdtDiaMesItem.ValorItem = &Diaselecionado &DiaClicado = &SdtDiaMesItem.VAlorData do 'MontaCalendario' Exit EndiF EndFor
Refresh
btnAnterior.SetFocus()
EndSub
Sub 'MontaCalendario'
do 'limpaCampos'
&SdtDiaMes.Clear() &ano = Year(&DataBase) &Mes = month(&DataBase)
textMes.Caption = UPPER(&DataBase.MonthName()) + '/' + trim(str(&ano)) &DataInicialMes = yMDtoD(&ano, &Mes, 1) &DataFinal = EoM(&DataInicialMes) &QtdDias = Day(&DataFinal)
&diaSemana = &DataInicialMes.DayOfWeek() &item = &diaSemana
For &index = 1 to &QtdDias
&DataNova = yMDtoD(&ano, &Mes, &index)
do 'preenchecampo'
&item += 1 EndFor
EndSub
Sub 'preenchecampo'
&sdtDiaMesItem = new() &SdtDiaMesItem.ValorData = &DataNova &SdtDiaMesItem.ValorItem = &item &SdtDiaMesItem.ValorDia = &index &SdtDiaMes.Add(&SdtDiaMesItem)
&IsExiste = RetornaExisteCompromissoDia.udp(&Context.EmpCod, &Context.PesCod, &DataNova)
Do Case Case &DiaClicado = &DataNova if &IsExiste = true &Classe = 'Btn_PequenoAzulVermelho' Else &Classe = 'Btn_PequenoIncolorVermelho' EndiF
Case &IsExiste = true &Classe = 'Btn_PequenoAzul' Otherwise &Classe = 'Btn_PequenoIncolor' EndCAse
do Case Case &Item = 1 btnacao1.Caption = trim(str(&index)) btnAcao1.Class = &Classe Case &Item = 2 btnacao2.Caption = trim(str(&index)) btnAcao2.Class = &Classe Case &Item = 3 btnacao3.Caption = trim(str(&index)) btnAcao3.Class = &Classe Case &Item = 4 btnacao4.Caption = trim(str(&index)) btnAcao4.Class = &Classe Case &Item = 5 btnacao5.Caption = trim(str(&index)) btnAcao5.Class = &Classe Case &Item = 6 btnacao6.Caption = trim(str(&index)) btnAcao6.Class = &Classe Case &Item = 7 btnacao7.Caption = trim(str(&index)) btnAcao7.Class = &Classe Case &Item = 8 btnacao11.Caption = trim(str(&index)) btnAcao11.Class = &Classe Case &Item = 9 btnacao12.Caption = trim(str(&index)) btnAcao12.Class = &Classe Case &Item = 10 btnacao13.Caption = trim(str(&index)) btnAcao13.Class = &Classe Case &Item = 11 btnacao14.Caption = trim(str(&index)) btnAcao14.Class = &Classe Case &Item = 12 btnacao15.Caption = trim(str(&index)) btnAcao15.Class = &Classe Case &Item = 13 btnacao16.Caption = trim(str(&index)) btnAcao16.Class = &Classe Case &Item = 14 btnacao17.Caption = trim(str(&index)) btnAcao17.Class = &Classe Case &Item = 15 btnacao21.Caption = trim(str(&index)) btnAcao21.Class = &Classe Case &Item = 16 btnacao22.Caption = trim(str(&index)) btnAcao22.Class = &Classe Case &Item = 17 btnacao23.Caption = trim(str(&index)) btnAcao23.Class = &Classe Case &Item = 18 btnacao24.Caption = trim(str(&index)) btnAcao24.Class = &Classe Case &Item = 19 btnacao25.Caption = trim(str(&index)) btnAcao25.Class = &Classe Case &Item = 20 btnacao26.Caption = trim(str(&index)) btnAcao26.Class = &Classe Case &Item = 21 btnacao27.Caption = trim(str(&index)) btnAcao27.Class = &Classe Case &Item = 22 btnacao31.Caption = trim(str(&index)) btnAcao31.Class = &Classe Case &Item = 23 btnacao32.Caption = trim(str(&index)) btnAcao32.Class = &Classe Case &Item = 24 btnacao33.Caption = trim(str(&index)) btnAcao33.Class = &Classe Case &Item = 25 btnacao34.Caption = trim(str(&index)) btnAcao34.Class = &Classe Case &Item = 26 btnacao35.Caption = trim(str(&index)) btnAcao35.Class = &Classe Case &Item = 27 btnacao36.Caption = trim(str(&index)) btnAcao36.Class = &Classe Case &Item = 28 btnacao37.Caption = trim(str(&index)) btnAcao37.Class = &Classe Case &Item = 29 btnacao41.Caption = trim(str(&index)) btnAcao41.Class = &Classe Case &Item = 30 btnacao42.Caption = trim(str(&index)) btnAcao42.Class = &Classe Case &Item = 31 btnacao43.Caption = trim(str(&index)) btnAcao43.Class = &Classe Case &Item = 32 btnacao44.Caption = trim(str(&index)) btnAcao44.Class = &Classe Case &Item = 33 btnacao45.Caption = trim(str(&index)) btnAcao45.Class = &Classe Case &Item = 34 btnacao46.Caption = trim(str(&index)) btnAcao46.Class = &Classe Case &Item = 35 btnacao47.Caption = trim(str(&index)) btnAcao47.Class = &Classe Case &Item = 36 btnacao51.Caption = trim(str(&index)) btnAcao51.Class = &Classe Case &Item = 37 btnacao52.Caption = trim(str(&index)) btnAcao52.Class = &Classe Case &Item = 38 btnacao53.Caption = trim(str(&index)) btnAcao53.Class = &Classe Case &Item = 39 btnacao54.Caption = trim(str(&index)) btnAcao54.Class = &Classe Case &Item = 40 btnacao55.Caption = trim(str(&index)) btnAcao55.Class = &Classe Case &Item = 41 btnacao56.Caption = trim(str(&index)) btnAcao56.Class = &Classe Case &Item = 42 btnacao57.Caption = trim(str(&index)) btnAcao57.Class = &Classe EndCase
