Sub 'limpaCampos'
//1 semana btnacao1.Caption = '' btnacao2.Caption = '' btnacao3.Caption = '' btnacao4.Caption = '' btnacao5.Caption = '' btnacao6.Caption = '' btnacao7.Caption = ''
